  ($lum$0ab36e90-d793-5048-a860-3de9602c85e6$lum$::uuid, $lum$prompting$lum$, $lum$Prompting$lum$, $lum$topic$lum$),
  ($lum$19bc75db-e505-589c-9dcd-c946497db8e0$lum$::uuid, $lum$framing$lum$, $lum$Framing & briefs$lum$, $lum$topic$lum$),
  ($lum$3b4ba4ed-3a85-5699-9433-c2f44c19f308$lum$::uuid, $lum$hallucinations$lum$, $lum$Accuracy & hallucinations$lum$, $lum$topic$lum$),
  ($lum$0817572c-d973-5e8f-a4a5-0044528791d9$lum$::uuid, $lum$custom-instructions$lum$, $lum$Custom instructions$lum$, $lum$topic$lum$),
